using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Build the graph
    unordered_map<long long, vector<pair<long long, long long>>> graph;
    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        graph[u].push_back({v, w});
        graph[v].push_back({u, w});
    }

    // Use a priority queue to keep track of the maximum edge weights in each component
    priority_queue<long long> maxEdges;

    // Use a Disjoint Set Union (DSU) structure to manage connected components
    vector<long long> parent(n);
    vector<long long> rank(n);

    // Initialize DSU
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        rank[i] = 1;
    }

    // Function to find the root of a node
    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Function to perform union of two sets
    bool unionSets(long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX == rootY) {
            return false; // Already in the same set
        }
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else {
            parent[rootY] = rootX;
            if (rank[rootX] == rank[rootY]) {
                rank[rootX]++;
            }
        }
        return true;
    }

    // Use Kruskal's algorithm to process edges in increasing order of weight
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    // Process edges and track the maximum edge weight in each component
    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        if (unionSets(u, v)) {
            maxEdges.push(w);
        }
    }

    // We need to split the graph into at most k components
    // So we need to remove the (total_components - k) largest edges
    long long totalComponents = n;
    long long removeCount = totalComponents - k;
    for (long long i = 0; i < removeCount && !maxEdges.empty(); ++i) {
        maxEdges.pop();
    }

    // The answer is the maximum edge weight in the remaining components
    return maxEdges.empty() ? 0 : maxEdges.top();
